/**
 * Template: business-logic provider test file
 */
import type { ProviderYaml } from './provider-yaml.types.js';

export function renderProviderTest(cfg: ProviderYaml): string {
  const key = cfg.name.toUpperCase().replace(/-/g, '_');
  const models = Object.keys(cfg.models);
  const modelChecks = models.map((m) => `    '${m}',`).join('\n');

  return `/**
 * @generated by @flusk/cli — provider generator
 */
import { describe, it, expect } from 'vitest';
import { ${key}_PRICING } from './${cfg.name}.pricing.js';
import { ${key}_SYSTEM_VALUES, ${key}_MODEL_PREFIXES } from './${cfg.name}.span-config.js';

describe('${cfg.name} provider', () => {
  it('has pricing for all known models', () => {
    const expected = [
${modelChecks}
    ];
    for (const m of expected) {
      expect(${key}_PRICING[m]).toBeDefined();
    }
  });

  it('has system values', () => {
    expect(${key}_SYSTEM_VALUES.length).toBeGreaterThan(0);
  });

  it('has model prefixes', () => {
    expect(${key}_MODEL_PREFIXES.length).toBeGreaterThan(0);
  });
});
`;
}
